// // This module inverts the state of the 8-bit switch input before transferring it to the 8-bit output LED representation.
module top_module(SW , CLOCK_50 , LEDR );input [7:0] SW;
    input CLOCK_50;


    output reg [7:0] LEDR;

    always @(posedge CLOCK_50)
        LEDR [7:0] <= SW [7:0];

endmodule
